// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100005
#define MAX_R 55
#define MAX_C 1000000005

// Structure to represent an edge
typedef struct Edge {
    int to;
    int length;
    struct Edge* next;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int n;
    Edge** edges;
} Graph;

// Function to create a new edge
Edge* createEdge(int to, int length) {
    Edge* edge = (Edge*)malloc(sizeof(Edge));
    edge->to = to;
    edge->length = length;
    edge->next = NULL;
    return edge;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int from, int to, int length) {
    Edge* edge = createEdge(to, length);
    edge->next = graph->edges[from];
    graph->edges[from] = edge;
}

// Function to perform DFS and find the minimum median
int dfs(Graph* graph, int node, int parent, int depth, int* path, int* lengths, int L, int R) {
    if (depth >= L && depth <= R) {
        // Calculate the median of the edge lengths
        int median = 0;
        int* sortedLengths = (int*)malloc(depth * sizeof(int));
        for (int i = 0; i < depth; i++) {
            sortedLengths[i] = lengths[i];
        }
        qsort(sortedLengths, depth, sizeof(int), compare);
        if (depth % 2 == 0) {
            median = (sortedLengths[depth / 2 - 1] + sortedLengths[depth / 2]) / 2;
        } else {
            median = sortedLengths[depth / 2];
        }
        free(sortedLengths);
        return median;
    }
    int minMedian = INT_MAX;
    Edge* edge = graph->edges[node];
    while (edge != NULL) {
        if (edge->to != parent) {
            path[depth] = edge->to;
            lengths[depth] = edge->length;
            int median = dfs(graph, edge->to, node, depth + 1, path, lengths, L, R);
            if (median < minMedian) {
                minMedian = median;
            }
        }
        edge = edge->next;
    }
    return minMedian;
}

// Function to compare two integers
int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, L, R;
        scanf("%d %d %d", &N, &L, &R);
        Graph* graph = (Graph*)malloc(sizeof(Graph));
        graph->n = N;
        graph->edges = (Edge**)malloc(N * sizeof(Edge*));
        for (int i = 0; i < N; i++) {
            graph->edges[i] = NULL;
        }
        for (int i = 0; i < N - 1; i++) {
            int from, to, length;
            scanf("%d %d %d", &from, &to, &length);
            addEdge(graph, from - 1, to - 1, length);
            addEdge(graph, to - 1, from - 1, length);
        }
        int* path = (int*)malloc(R * sizeof(int));
        int* lengths = (int*)malloc(R * sizeof(int));
        int minMedian = INT_MAX;
        for (int i = 0; i < N; i++) {
            int median = dfs(graph, i, -1, 0, path, lengths, L, R);
            if (median < minMedian) {
                minMedian = median;
            }
        }
        if (minMedian == INT_MAX) {
            printf("-1\n");
        } else {
            printf("%d\n", minMedian);
        }
        free(path);
        free(lengths);
        for (int i = 0; i < N; i++) {
            Edge* edge = graph->edges[i];
            while (edge != NULL) {
                Edge* next = edge->next;
                free(edge);
                edge = next;
            }
        }
        free(graph->edges);
        free(graph);
    }
    return 0;
}

