using namespace std;

// Structure to represent an edge
struct Edge {
    int to;
    int length;
};

// Function to perform DFS and find the minimum median
int dfs(vector<vector<Edge>>& graph, int node, int parent, int depth, vector<int>& path, vector<int>& lengths, int L, int R) {
    if (depth >= L && depth <= R) {
        // Calculate the median of the edge lengths
        sort(lengths.begin(), lengths.begin() + depth);
        int median = 0;
        if (depth % 2 == 0) {
            median = (lengths[depth / 2 - 1] + lengths[depth / 2]) / 2;
        } else {
            median = lengths[depth / 2];
        }
        return median;
    }
    int minMedian = numeric_limits<int>::max();
    for (const auto& edge : graph[node]) {
        if (edge.to != parent) {
            path.push_back(edge.to);
            lengths.push_back(edge.length);
            int median = dfs(graph, edge.to, node, depth + 1, path, lengths, L, R);
            if (median < minMedian) {
                minMedian = median;
            }
            path.pop_back();
            lengths.pop_back();
        }
    }
    return minMedian;
}

