    static class Edge {
        int to;
        int length;

        public Edge(int to, int length) {
            this.to = to;
            this.length = length;
        }
    }

    // Function to perform DFS and find the minimum median
    public static int dfs(List<List<Edge>> graph, int node, int parent, int depth, List<Integer> path, List<Integer> lengths, int L, int R) {
        if (depth >= L && depth <= R) {
            // Calculate the median of the edge lengths
            Collections.sort(lengths);
            int median = 0;
            if (depth % 2 == 0) {
                median = (lengths.get(depth / 2 - 1) + lengths.get(depth / 2)) / 2;
            } else {
                median = lengths.get(depth / 2);
            }
            return median;
        }
        int minMedian = Integer.MAX_VALUE;
        for (Edge edge : graph.get(node)) {
            if (edge.to != parent) {
                path.add(edge.to);
                lengths.add(edge.length);
                int median = dfs(graph, edge.to, node, depth + 1, path, lengths, L, R);
                if (median < minMedian) {
                    minMedian = median;
                }
                path.remove(path.size() - 1);
                lengths.remove(lengths.size() - 1);
            }
        }
        return minMedian;
    }

