            for (int i = 0; i < N; i++) {
                graph.add(new ArrayList<>());
            }
            for (int i = 0; i < N - 1; i++) {
                int from = scanner.nextInt() - 1;
                int to = scanner.nextInt() - 1;
                int length = scanner.nextInt();
                graph.get(from).add(new Edge(to, length));
                graph.get(to).add(new Edge(from, length));
            }
            List<Integer> path = new ArrayList<>();
            List<Integer> lengths = new ArrayList<>();
            int minMedian = Integer.MAX_VALUE;
            for (int i = 0; i < N; i++) {
                int median = dfs(graph, i, -1, 0, path, lengths, L, R);
                if (median < minMedian) {
                    minMedian = median;
                }
            }
            if (minMedian == Integer.MAX_VALUE) {
                System.out.println(-1);
            } else {
                System.out.println(minMedian);
            }
        }
    }
